DROP PROCEDURE IF EXISTS `sp_cari_pembayaran`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_cari_pembayaran` (IN `p_month` TINYINT, IN `p_year` YEAR)   BEGIN
    SELECT
        p.payment_id,
        t.full_name,
        k.kost_name,
        p.payment_date,
        p.amount,
        p.payment_status
    FROM payment p
    JOIN rental r ON p.rental_id = r.rental_id
    JOIN tenant t ON r.tenant_id = t.tenant_id
    JOIN room rm ON r.room_id = rm.room_id
    JOIN kost k ON rm.kost_id = k.kost_id
    WHERE p.payment_month = p_month
      AND p.payment_year = p_year;
END$$

DROP PROCEDURE IF EXISTS `sp_kategori_kapasitas_kost`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_kategori_kapasitas_kost` ()   BEGIN
    -- Deklarasi variabel
    DECLARE v_done INT DEFAULT FALSE;
    DECLARE v_kost_name VARCHAR(100);
    DECLARE v_total_room INT;
    DECLARE v_kategori VARCHAR(50);

    -- Deklarasi Cursor untuk mengambil data kost
    DECLARE cur_kost CURSOR FOR 
        SELECT kost_name, total_room FROM kost;

    -- Deklarasi Handler untuk menghentikan LOOP saat data habis
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = TRUE;

    -- Membuat tabel temporary untuk menampung hasil eksekusi Cursor
    CREATE TEMPORARY TABLE IF NOT EXISTS temp_hasil_kategori (
        kost_name VARCHAR(100),
        total_room INT,
        kategori VARCHAR(50)
    );
    TRUNCATE TABLE temp_hasil_kategori;

    -- Membuka Cursor
    OPEN cur_kost;

    -- Memulai LOOP
    read_loop: LOOP
        -- Mengambil data baris per baris ke dalam variabel
        FETCH cur_kost INTO v_kost_name, v_total_room;

        -- Control Flow (IF) untuk menghentikan LOOP jika tidak ada data lagi
        IF v_done THEN
            LEAVE read_loop;
        END IF;

        -- Control Flow (IF..ELSEIF) untuk menentukan kategori skala kost
        IF v_total_room >= 50 THEN
            SET v_kategori = 'Kost Skala Besar';
        ELSEIF v_total_room >= 20 THEN
            SET v_kategori = 'Kost Skala Menengah';
        ELSE
            SET v_kategori = 'Kost Skala Kecil';
        END IF;

        -- Menyimpan data yang sudah diproses ke tabel temporary
        VALUES (v_kost_name, v_total_room, v_kategori);
        
    END LOOP;

    -- Menutup Cursor
    CLOSE cur_kost;

    -- Menampilkan hasil akhir dari tabel temporary
    SELECT * FROM temp_hasil_kategori;
    
    -- Menghapus tabel temporary agar bersih kembali
    DROP TEMPORARY TABLE temp_hasil_kategori;
END$$

DROP PROCEDURE IF EXISTS `sp_statistik_kost`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_statistik_kost` ()   BEGIN
    SELECT
        (SELECT COUNT(*) FROM owner) AS total_owner,
        (SELECT COUNT(*) FROM kost) AS total_kost,
        (SELECT COUNT(*) FROM room) AS total_room,
        (SELECT COUNT(*) FROM tenant) AS total_tenant,
        (SELECT COUNT(*) FROM rental) AS total_rental,
        (SELECT COUNT(*) FROM payment) AS total_payment;
END$$

--
-- Functions
--
DROP FUNCTION IF EXISTS `fn_total_income`$$
CREATE DEFINER=`root`@`localhost` FUNCTION `fn_total_income` (`p_month` TINYINT, `p_year` YEAR) RETURNS DECIMAL(15,2) DETERMINISTIC READS SQL DATA BEGIN
    DECLARE total_income DECIMAL(15,2);

    SELECT IFNULL(SUM(amount),0)
    INTO total_income
    FROM payment
    WHERE payment_month = p_month
      AND payment_year = p_year
      AND payment_status = 'Paid';

    RETURN total_income;
END$$

DROP FUNCTION IF EXISTS `fn_total_paid`$$
CREATE DEFINER=`root`@`localhost` FUNCTION `fn_total_paid` () RETURNS INT(11) DETERMINISTIC READS SQL DATA BEGIN
    DECLARE total INT;

    SELECT COUNT(*)
    INTO total
    FROM payment
    WHERE payment_status='Paid';

    RETURN total;
END$$

